14	// Using 0-indexed internally for stacks and box values for convenience with vectors
15	// Box values 0 to N-1, stack indices 0 to M-1.
16	// Input is 1-indexed for box values (1 to N) and stack indices (1 to M).
17	// Output must be 1-indexed for box values and stack indices.
18	// target_stack_idx=0 for carry-out operation.
19	
20	// Constants for heuristic evaluation
21	const double HEURISTIC_EMPTY_STACK_BONUS_SCORE = 1000.0;
22	const double STACK_HEIGHT_PENALTY_FACTOR = 0.1;
23	const int HEURISTIC_LOOKAHEAD_WINDOW = 5;
24	const double HEURISTIC_COVER_CRITICAL_PENALTY_PER_BOX_ABOVE = 3.0;
25	const double HEURISTIC_MIN_LABEL_IN_DEST_FACTOR = 0.05;
26	
27	// SA Parameters
28	const double TIME_LIMIT_SECONDS_TOTAL = 1.95; 
29	double BEAM_SEARCH_TIME_LIMIT_SECONDS_PARAM = 0.30; 
30	const int BEAM_WIDTH = 5; 
31	double T_INITIAL_SA = 75.0;  
32	double T_FINAL_SA = 0.01;   
