316	struct SimulationResult {
317	    long long energy_cost;
318	    std::vector<std::pair<int, int>> ops_history;
319	};
320	
321	std::pair<State, long long> simulate_up_to_k(
322	    const std::vector<std::vector<int>>& initial_stacks_param,
323	    const std::vector<int>& plan_D,
324	    int N_CONST, int M_CONST,
325	    int k_limit_box_idx) { 
326	    
327	    State current_sim_state(N_CONST, M_CONST, initial_stacks_param, false); 
328	    
329	    for (int k_target_box = 0; k_target_box < k_limit_box_idx; ++k_target_box) {
330	        int target_box_val = k_target_box; 
331	        int src_stack_idx = current_sim_state.box_pos[target_box_val].first;
332	        int height_idx = current_sim_state.box_pos[target_box_val].second;
333	        int num_boxes_on_top = current_sim_state.stacks[src_stack_idx].size() - 1 - height_idx;
334	
335	        if (num_boxes_on_top > 0) { 
336	            int op1_first_box_in_block_val = current_sim_state.stacks[src_stack_idx][height_idx + 1];
337	            int actual_dest_stack_idx = plan_D[k_target_box];
338	            
339	            if (actual_dest_stack_idx == src_stack_idx && M_CONST > 1) {
340	                actual_dest_stack_idx = (src_stack_idx + 1) % M_CONST;
341	            }
342	            
343	            if (M_CONST > 1) {
344	                 current_sim_state.apply_op1_move(op1_first_box_in_block_val, num_boxes_on_top, actual_dest_stack_idx);
345	            }
346	        }
347	        current_sim_state.apply_op2_carry_out(target_box_val);
348	    }
349	    long long final_energy = current_sim_state.energy_cost; // Store before move
350	    return {std::move(current_sim_state), final_energy};
351	}
352	
353	SimulationResult run_simulation_from_intermediate_state(
354	    State intermediate_state, 
355	    const std::vector<int>& plan_D,
356	    int k_start_box_idx,      
357	    int N_CONST, int M_CONST,
358	    bool record_ops_for_suffix) {
359	
360	    State current_sim_state = std::move(intermediate_state); 
361	    
362	    if (record_ops_for_suffix) {
363	        current_sim_state.ops_history.clear(); 
364	        current_sim_state.record_ops_flag = true;
365	    } else {
366	        current_sim_state.record_ops_flag = false;
367	    }
368	
369	    for (int k_target_box = k_start_box_idx; k_target_box < N_CONST; ++k_target_box) {
370	        int target_box_val = k_target_box; 
371	        int src_stack_idx = current_sim_state.box_pos[target_box_val].first;
372	        int height_idx = current_sim_state.box_pos[target_box_val].second;
373	        int num_boxes_on_top = current_sim_state.stacks[src_stack_idx].size() - 1 - height_idx;
374	
375	        if (num_boxes_on_top > 0) {
376	            int op1_first_box_in_block_val = current_sim_state.stacks[src_stack_idx][height_idx + 1];
377	            int actual_dest_stack_idx = plan_D[k_target_box];
378	            
379	            if (actual_dest_stack_idx == src_stack_idx && M_CONST > 1) {
380	                actual_dest_stack_idx = (src_stack_idx + 1) % M_CONST;
381	            }
382	
383	            if (M_CONST > 1) {
384	                 current_sim_state.apply_op1_move(op1_first_box_in_block_val, num_boxes_on_top, actual_dest_stack_idx);
385	            }
386	        }
387	        current_sim_state.apply_op2_carry_out(target_box_val);
388	    }
389	    return {current_sim_state.energy_cost, std::move(current_sim_state.ops_history)};
390	}
391	
392	SimulationResult run_simulation(const std::vector<std::vector<int>>& initial_stacks_param,
393	                                const std::vector<int>& plan_D, int N_CONST, int M_CONST, bool record_all_ops = true) {
394	    State initial_state_for_full_sim(N_CONST, M_CONST, initial_stacks_param, record_all_ops);
395	    return run_simulation_from_intermediate_state(std::move(initial_state_for_full_sim), plan_D, 0, N_CONST, M_CONST, record_all_ops);
396	}
