# EVOLVE-BLOCK-START
#include <iostream>
#include <vector>
#include <string>
#include <algorithm>
#include <limits>
#include <chrono>
#include <random>
#include <cmath>
#include <utility>
#include <numeric>

// 0-indexed internally. Input/output 1-indexed.
// N=200 boxes, M=10 stacks, each starts with 20 boxes.

const double TIME_LIMIT_SECONDS = 1.95;
const double BEAM_TIME_FRACTION = 0.40;
const int BEAM_WIDTH = 15;

auto GLOBAL_START_TIME = std::chrono::steady_clock::now();

struct RandomGenerator {
    std::mt19937 rng;
    RandomGenerator() : rng(std::chrono::steady_clock::now().time_since_epoch().count()) {}
    int an_int(int lo, int hi) {
        if (lo > hi) return lo;
        return std::uniform_int_distribution<int>(lo, hi)(rng);
    }
    double a_double(double lo, double hi) {
        return std::uniform_real_distribution<double>(lo, hi)(rng);
    }
} RGen;

double elapsed_seconds() {
    return std::chrono::duration<double>(std::chrono::steady_clock::now() - GLOBAL_START_TIME).count();
}

// Plan entry for each box k:
// If split == 0: move all boxes above k to dest1. Cost = above+1
// If split > 0: move top 'split' boxes to dest1, then remaining (above-split) to dest2. Cost = above+2
struct PlanEntry {
    int dest1;
    int dest2;
    int split; // 0 = no split; >0 = number of boxes moved in first (top) sub-move
};

struct State {
    std::vector<std::vector<int>> stacks; // stacks[i] = boxes from bottom to top (0-indexed values)
    std::vector<std::pair<int,int>> box_pos; // box_pos[v] = {stack_idx, height_idx}
    long long energy;
    int N, M;

    State() : energy(0), N(0), M(0) {}

    State(int n, int m, const std::vector<std::vector<int>>& init_stacks)
        : energy(0), N(n), M(m) {
        stacks.resize(M);
        box_pos.resize(N);
        for (int i = 0; i < M; i++) {
            stacks[i].reserve(N);
            for (int j = 0; j < (int)init_stacks[i].size(); j++) {
                int v = init_stacks[i][j] - 1; // 0-indexed
                stacks[i].push_back(v);
                box_pos[v] = {i, j};
            }
        }
    }

    void move_block(int first_box_val, int count, int dest_idx) {
        int src_idx = box_pos[first_box_val].first;
        int start_h = box_pos[first_box_val].second;
        auto& src = stacks[src_idx];
        auto& dst = stacks[dest_idx];
        int old_dst_h = dst.size();
        dst.insert(dst.end(), src.begin() + start_h, src.begin() + start_h + count);
        src.erase(src.begin() + start_h, src.begin() + start_h + count);
        for (int i = 0; i < count; i++) {
            int v = dst[old_dst_h + i];
            box_pos[v] = {dest_idx, old_dst_h + i};
        }
        energy += count + 1;
    }

    void carry_out(int box_val) {
        int si = box_pos[box_val].first;
        stacks[si].pop_back();
    }

    // Evaluate how good it is to place a block on dest_idx
    // Lower score = better destination
    double eval_dest(int target_val, const std::vector<int>& block, int dest_idx) const {
        const auto& dst = stacks[dest_idx];
        double score = 0.0;

        if (dst.empty()) {
            score -= 800.0;
        } else {
            // Penalty for burying soon-needed boxes in destination
            for (int b : dst) {
                if (b > target_val && b < target_val + 30) {
                    // b needs to come out relatively soon; placing block on top means
                    // block.size() extra boxes above b when b's turn comes
                    double urgency = 30.0 / (b - target_val);
                    score += urgency * block.size();
                }
            }
            score += dst.size() * 0.05;
        }

        // Penalty for boxes in the block that will be buried by other block boxes
        for (int i = 0; i < (int)block.size(); i++) {
            int b = block[i]; // block[0] is bottom of block, block.back() is top
            if (b > target_val && b < target_val + 30) {
                int boxes_above_in_block = block.size() - 1 - i;
                double urgency = 30.0 / (b - target_val);
                score += urgency * boxes_above_in_block;
            }
        }

        // Bonus for placing blocks where the minimum label is large (less critical)
        if (!dst.empty()) {
            int min_in_dst = *std::min_element(dst.begin(), dst.end());
            score -= min_in_dst * 0.02;
        }

        return score;
    }
};

struct SimResult {
    long long energy;
    std::vector<std::pair<int,int>> ops; // (box_val+1, dest+1) or (box_val+1, 0)
};

// Execute plan on initial state, return total energy and optionally operations
SimResult simulate(const std::vector<std::vector<int>>& init_stacks, const std::vector<PlanEntry>& plan,
                   int N, int M, bool record_ops) {
    State st(N, M, init_stacks);
    std::vector<std::pair<int,int>> ops;
    if (record_ops) ops.reserve(N * 3);

    for (int k = 0; k < N; k++) {
        int target = k;
        int si = st.box_pos[target].first;
        int hi = st.box_pos[target].second;
        int above = (int)st.stacks[si].size() - 1 - hi;

        if (above > 0) {
            const auto& pe = plan[k];
            if (pe.split > 0 && pe.split < above) {
                // Split move: first move top 'split' boxes to dest1
                int top_start_h = hi + 1 + (above - pe.split); // first box of top portion
                int top_first_val = st.stacks[si][top_start_h];
                int d1 = pe.dest1;
                if (d1 == si) d1 = (si + 1) % M;
                if (record_ops) ops.push_back({top_first_val + 1, d1 + 1});
                st.move_block(top_first_val, pe.split, d1);

                // Now move remaining (above - split) boxes to dest2
                // Recalculate position since state changed
                si = st.box_pos[target].first;
                hi = st.box_pos[target].second;
                int remaining = (int)st.stacks[si].size() - 1 - hi;
                if (remaining > 0) {
                    int bot_first_val = st.stacks[si][hi + 1];
                    int d2 = pe.dest2;
                    if (d2 == si) d2 = (si + 1) % M;
                    if (d2 == d1 && M > 2) {
                        // Try to pick a different dest if possible, but plan says dest2
                        // Keep it as plan says, just ensure it's not same as source
                    }
                    if (record_ops) ops.push_back({bot_first_val + 1, d2 + 1});
                    st.move_block(bot_first_val, remaining, d2);
                }
            } else {
                // Single move: move all above to dest1
                int first_val = st.stacks[si][hi + 1];
                int d1 = pe.dest1;
                if (d1 == si) d1 = (si + 1) % M;
                if (record_ops) ops.push_back({first_val + 1, d1 + 1});
                st.move_block(first_val, above, d1);
            }
        }
        if (record_ops) ops.push_back({target + 1, 0});
        st.carry_out(target);
    }
    return {st.energy, std::move(ops)};
}

// Simulate from step k_start given a pre-built state, return energy from k_start onwards
long long simulate_suffix(State st, const std::vector<PlanEntry>& plan, int k_start, int N, int M) {
    long long base_energy = st.energy;
    for (int k = k_start; k < N; k++) {
        int target = k;
        int si = st.box_pos[target].first;
        int hi = st.box_pos[target].second;
        int above = (int)st.stacks[si].size() - 1 - hi;

        if (above > 0) {
            const auto& pe = plan[k];
            if (pe.split > 0 && pe.split < above) {
                int top_start_h = hi + 1 + (above - pe.split);
                int top_first_val = st.stacks[si][top_start_h];
                int d1 = pe.dest1;
                if (d1 == si) d1 = (si + 1) % M;
                st.move_block(top_first_val, pe.split, d1);

                si = st.box_pos[target].first;
                hi = st.box_pos[target].second;
                int remaining = (int)st.stacks[si].size() - 1 - hi;
                if (remaining > 0) {
                    int bot_first_val = st.stacks[si][hi + 1];
                    int d2 = pe.dest2;
                    if (d2 == si) d2 = (si + 1) % M;
                    st.move_block(bot_first_val, remaining, d2);
                }
            } else {
                int first_val = st.stacks[si][hi + 1];
                int d1 = pe.dest1;
                if (d1 == si) d1 = (si + 1) % M;
                st.move_block(first_val, above, d1);
            }
        }
        st.carry_out(target);
    }
    return st.energy;
}

// Build state up to step k (exclusive) using plan
State build_state_at(const std::vector<std::vector<int>>& init_stacks, const std::vector<PlanEntry>& plan,
                     int k_limit, int N, int M) {
    State st(N, M, init_stacks);
    for (int k = 0; k < k_limit; k++) {
        int target = k;
        int si = st.box_pos[target].first;
        int hi = st.box_pos[target].second;
        int above = (int)st.stacks[si].size() - 1 - hi;

        if (above > 0) {
            const auto& pe = plan[k];
            if (pe.split > 0 && pe.split < above) {
                int top_start_h = hi + 1 + (above - pe.split);
                int top_first_val = st.stacks[si][top_start_h];
                int d1 = pe.dest1;
                if (d1 == si) d1 = (si + 1) % M;
                st.move_block(top_first_val, pe.split, d1);

                si = st.box_pos[target].first;
                hi = st.box_pos[target].second;
                int remaining = (int)st.stacks[si].size() - 1 - hi;
                if (remaining > 0) {
                    int bot_first_val = st.stacks[si][hi + 1];
                    int d2 = pe.dest2;
                    if (d2 == si) d2 = (si + 1) % M;
                    st.move_block(bot_first_val, remaining, d2);
                }
            } else {
                int first_val = st.stacks[si][hi + 1];
                int d1 = pe.dest1;
                if (d1 == si) d1 = (si + 1) % M;
                st.move_block(first_val, above, d1);
            }
        }
        st.carry_out(target);
    }
    return st;
}

// Greedy solution: for each step, pick best destination using heuristic
std::vector<PlanEntry> greedy_plan(const std::vector<std::vector<int>>& init_stacks, int N, int M) {
    State st(N, M, init_stacks);
    std::vector<PlanEntry> plan(N);

    for (int k = 0; k < N; k++) {
        int target = k;
        int si = st.box_pos[target].first;
        int hi = st.box_pos[target].second;
        int above = (int)st.stacks[si].size() - 1 - hi;

        if (above == 0) {
            plan[k] = {si, si, 0};
            st.carry_out(target);
            continue;
        }

        // Collect the block above target
        std::vector<int> block(st.stacks[si].begin() + hi + 1, st.stacks[si].end());

        // Try no-split: find best single destination
        double best_score = std::numeric_limits<double>::max();
        int best_dest = (si + 1) % M;
        for (int d = 0; d < M; d++) {
            if (d == si) continue;
            double sc = st.eval_dest(target, block, d);
            if (sc < best_score) {
                best_score = sc;
                best_dest = d;
            }
        }

        // Try split: find best split point and destinations
        // Only try if above >= 2
        double best_split_score = std::numeric_limits<double>::max();
        int best_split = 0, best_d1 = -1, best_d2 = -1;

        if (above >= 2) {
            // Try a few split points
            for (int sp = 1; sp < above; sp++) {
                // Top portion: block[above-sp ... above-1] (sp boxes)
                std::vector<int> top_part(block.begin() + (above - sp), block.end());
                // Bottom portion: block[0 ... above-sp-1]
                std::vector<int> bot_part(block.begin(), block.begin() + (above - sp));

                // Find best dest for top part
                double best_top_sc = std::numeric_limits<double>::max();
                int best_top_d = (si + 1) % M;
                for (int d = 0; d < M; d++) {
                    if (d == si) continue;
                    double sc = st.eval_dest(target, top_part, d);
                    if (sc < best_top_sc) {
                        best_top_sc = sc;
                        best_top_d = d;
                    }
                }

                // For bottom part, evaluate on state AFTER top part moved
                // Approximate: just evaluate on current state but exclude top dest having top_part
                double best_bot_sc = std::numeric_limits<double>::max();
                int best_bot_d = (si + 1) % M;
                for (int d = 0; d < M; d++) {
                    if (d == si) continue;
                    double sc = st.eval_dest(target, bot_part, d);
                    // Slight penalty if same as top dest (stacking)
                    if (d == best_top_d) sc += 2.0;
                    if (sc < best_bot_sc) {
                        best_bot_sc = sc;
                        best_bot_d = d;
                    }
                }

                double total_split_sc = best_top_sc + best_bot_sc + 1.0; // +1 for extra energy cost of split
                if (total_split_sc < best_split_score) {
                    best_split_score = total_split_sc;
                    best_split = sp;
                    best_d1 = best_top_d;
                    best_d2 = best_bot_d;
                }
            }
        }

        // Compare no-split vs split
        if (best_split > 0 && best_split_score < best_score - 0.5) {
            plan[k] = {best_d1, best_d2, best_split};
            // Execute split
            int top_start_h = hi + 1 + (above - best_split);
            int top_first_val = st.stacks[si][top_start_h];
            int d1 = best_d1;
            if (d1 == si) d1 = (si + 1) % M;
            st.move_block(top_first_val, best_split, d1);

            si = st.box_pos[target].first;
            hi = st.box_pos[target].second;
            int remaining = (int)st.stacks[si].size() - 1 - hi;
            if (remaining > 0) {
                int bot_first_val = st.stacks[si][hi + 1];
                int d2 = best_d2;
                if (d2 == si) d2 = (si + 1) % M;
                st.move_block(bot_first_val, remaining, d2);
            }
        } else {
            plan[k] = {best_dest, best_dest, 0};
            int first_val = st.stacks[si][hi + 1];
            int d1 = best_dest;
            if (d1 == si) d1 = (si + 1) % M;
            st.move_block(first_val, above, d1);
        }
        st.carry_out(target);
    }
    return plan;
}

// Beam search for initial plan (no splits, simpler)
std::vector<PlanEntry> beam_search_plan(const std::vector<std::vector<int>>& init_stacks,
                                         int N, int M, int beam_width, double time_budget) {
    struct BNode {
        State st;
        std::vector<PlanEntry> plan;
        bool operator<(const BNode& o) const { return st.energy < o.st.energy; }
    };

    std::vector<BNode> beam;
    beam.reserve(beam_width + 1);
    BNode init_node;
    init_node.st = State(N, M, init_stacks);
    init_node.plan.resize(N, {0, 0, 0});
    beam.push_back(std::move(init_node));

    std::vector<BNode> candidates;
    candidates.reserve(beam_width * M + 5);

    for (int k = 0; k < N; k++) {
        if (elapsed_seconds() > time_budget) {
            // Finish remaining with greedy
            if (beam.empty()) return greedy_plan(init_stacks, N, M);
            std::sort(beam.begin(), beam.end());
            BNode& best = beam[0];
            // Greedy finish
            for (int kk = k; kk < N; kk++) {
                int target = kk;
                int si = best.st.box_pos[target].first;
                int hi = best.st.box_pos[target].second;
                int above = (int)best.st.stacks[si].size() - 1 - hi;
                if (above == 0) {
                    best.plan[kk] = {si, si, 0};
                    best.st.carry_out(target);
                    continue;
                }
                std::vector<int> block(best.st.stacks[si].begin() + hi + 1, best.st.stacks[si].end());
                double best_sc = std::numeric_limits<double>::max();
                int best_d = (si + 1) % M;
                for (int d = 0; d < M; d++) {
                    if (d == si) continue;
                    double sc = best.st.eval_dest(target, block, d);
                    if (sc < best_sc) { best_sc = sc; best_d = d; }
                }
                best.plan[kk] = {best_d, best_d, 0};
                int fv = best.st.stacks[si][hi + 1];
                int d1 = best_d;
                if (d1 == si) d1 = (si + 1) % M;
                best.st.move_block(fv, above, d1);
                best.st.carry_out(target);
            }
            return best.plan;
        }

        candidates.clear();
        for (auto& node : beam) {
            int target = k;
            int si = node.st.box_pos[target].first;
            int hi = node.st.box_pos[target].second;
            int above = (int)node.st.stacks[si].size() - 1 - hi;

            if (above == 0) {
                BNode next;
                next.st = node.st;
                next.plan = node.plan;
                next.plan[k] = {si, si, 0};
                next.st.carry_out(target);
                candidates.push_back(std::move(next));
            } else {
                for (int d = 0; d < M; d++) {
                    if (d == si) continue;
                    BNode next;
                    next.st = node.st;
                    next.plan = node.plan;
                    next.plan[k] = {d, d, 0};
                    int fv = next.st.stacks[si][hi + 1];
                    next.st.move_block(fv, above, d);
                    next.st.carry_out(target);
                    candidates.push_back(std::move(next));
                }
            }
        }

        if (candidates.empty()) return greedy_plan(init_stacks, N, M);

        std::sort(candidates.begin(), candidates.end());
        beam.clear();
        for (int i = 0; i < std::min(beam_width, (int)candidates.size()); i++) {
            beam.push_back(std::move(candidates[i]));
        }
    }

    if (beam.empty()) return greedy_plan(init_stacks, N, M);
    std::sort(beam.begin(), beam.end());
    return beam[0].plan;
}

int main() {
    std::ios_base::sync_with_stdio(false);
    std::cin.tie(NULL);
    GLOBAL_START_TIME = std::chrono::steady_clock::now();

    int N, M;
    std::cin >> N >> M;
    std::vector<std::vector<int>> init_stacks(M, std::vector<int>(N / M));
    for (int i = 0; i < M; i++)
        for (int j = 0; j < N / M; j++)
            std::cin >> init_stacks[i][j];

    // Generate initial plan using beam search
    double beam_time = TIME_LIMIT_SECONDS * BEAM_TIME_FRACTION;
    std::vector<PlanEntry> plan = beam_search_plan(init_stacks, N, M, BEAM_WIDTH, beam_time);

    // Also try greedy with splits
    std::vector<PlanEntry> greedy_split_plan = greedy_plan(init_stacks, N, M);
    long long beam_energy = simulate(init_stacks, plan, N, M, false).energy;
    long long greedy_energy = simulate(init_stacks, greedy_split_plan, N, M, false).energy;

    std::vector<PlanEntry> best_plan;
    long long best_energy;
    if (greedy_energy < beam_energy) {
        best_plan = greedy_split_plan;
        best_energy = greedy_energy;
    } else {
        best_plan = plan;
        best_energy = beam_energy;
    }

    std::vector<PlanEntry> current_plan = best_plan;
    long long current_energy = best_energy;

    // SA phase
    double sa_start_time = elapsed_seconds();
    double sa_end_time = TIME_LIMIT_SECONDS - 0.03;
    double T_init = 50.0;
    double T_final = 0.01;

    int sa_iters = 0;
    while (true) {
        double now = elapsed_seconds();
        if (now >= sa_end_time) break;

        double progress = (now - sa_start_time) / (sa_end_time - sa_start_time);
        progress = std::min(1.0, std::max(0.0, progress));
        double T = T_init * std::pow(T_final / T_init, progress);

        std::vector<PlanEntry> new_plan = current_plan;
        int k_change;

        double op_rand = RGen.a_double(0, 1);

        if (op_rand < 0.3) {
            // Single point mutation: change destination
            k_change = RGen.an_int(0, N - 1);
            new_plan[k_change].dest1 = RGen.an_int(0, M - 1);
            if (new_plan[k_change].split == 0) {
                new_plan[k_change].dest2 = new_plan[k_change].dest1;
            }
        } else if (op_rand < 0.55) {
            // Block mutation
            int start = RGen.an_int(0, N - 1);
            int len = RGen.an_int(1, std::max(1, N / 12));
            k_change = N;
            for (int i = 0; i < len; i++) {
                int idx = (start + i) % N;
                k_change = std::min(k_change, idx);
                new_plan[idx].dest1 = RGen.an_int(0, M - 1);
                if (new_plan[idx].split == 0) {
                    new_plan[idx].dest2 = new_plan[idx].dest1;
                }
            }
        } else if (op_rand < 0.75) {
            // Toggle split on/off
            k_change = RGen.an_int(0, N - 1);
            if (new_plan[k_change].split == 0) {
                // Enable split with random parameters
                new_plan[k_change].split = RGen.an_int(1, 15); // will be clamped during sim
                new_plan[k_change].dest1 = RGen.an_int(0, M - 1);
                new_plan[k_change].dest2 = RGen.an_int(0, M - 1);
            } else {
                // Disable split
                new_plan[k_change].split = 0;
                new_plan[k_change].dest2 = new_plan[k_change].dest1;
            }
        } else if (op_rand < 0.90) {
            // Modify split parameters
            k_change = RGen.an_int(0, N - 1);
            if (new_plan[k_change].split > 0) {
                // Change split point or destinations
                double sub = RGen.a_double(0, 1);
                if (sub < 0.33) {
                    new_plan[k_change].split = RGen.an_int(1, 15);
                } else if (sub < 0.66) {
                    new_plan[k_change].dest1 = RGen.an_int(0, M - 1);
                } else {
                    new_plan[k_change].dest2 = RGen.an_int(0, M - 1);
                }
            } else {
                // Just change dest
                new_plan[k_change].dest1 = RGen.an_int(0, M - 1);
                new_plan[k_change].dest2 = new_plan[k_change].dest1;
            }
        } else {
            // Greedy re-evaluation of one step
            k_change = RGen.an_int(0, N - 1);
            State st_at_k = build_state_at(init_stacks, current_plan, k_change, N, M);
            int target = k_change;
            int si = st_at_k.box_pos[target].first;
            int hi = st_at_k.box_pos[target].second;
            int above = (int)st_at_k.stacks[si].size() - 1 - hi;

            if (above > 0) {
                std::vector<int> block(st_at_k.stacks[si].begin() + hi + 1, st_at_k.stacks[si].end());
                double best_sc = std::numeric_limits<double>::max();
                int best_d = (si + 1) % M;
                for (int d = 0; d < M; d++) {
                    if (d == si) continue;
                    double sc = st_at_k.eval_dest(target, block, d);
                    if (sc < best_sc) { best_sc = sc; best_d = d; }
                }
                new_plan[k_change] = {best_d, best_d, 0};

                // Also try splits
                if (above >= 2) {
                    for (int sp = 1; sp < above && sp <= 15; sp++) {
                        std::vector<int> top_part(block.begin() + (above - sp), block.end());
                        std::vector<int> bot_part(block.begin(), block.begin() + (above - sp));
                        double best_top_sc = std::numeric_limits<double>::max();
                        int best_top_d = (si + 1) % M;
                        for (int d = 0; d < M; d++) {
                            if (d == si) continue;
                            double sc = st_at_k.eval_dest(target, top_part, d);
                            if (sc < best_top_sc) { best_top_sc = sc; best_top_d = d; }
                        }
                        double best_bot_sc = std::numeric_limits<double>::max();
                        int best_bot_d = (si + 1) % M;
                        for (int d = 0; d < M; d++) {
                            if (d == si) continue;
                            double sc = st_at_k.eval_dest(target, bot_part, d);
                            if (d == best_top_d) sc += 2.0;
                            if (sc < best_bot_sc) { best_bot_sc = sc; best_bot_d = d; }
                        }
                        double total = best_top_sc + best_bot_sc + 1.0;
                        if (total < best_sc - 0.5) {
                            new_plan[k_change] = {best_top_d, best_bot_d, sp};
                            break;
                        }
                    }
                }
            } else {
                new_plan[k_change] = {si, si, 0};
            }
        }

        // Evaluate new plan
        long long new_energy;
        if (k_change == 0) {
            new_energy = simulate(init_stacks, new_plan, N, M, false).energy;
        } else {
            State st_at_k = build_state_at(init_stacks, new_plan, k_change, N, M);
            new_energy = simulate_suffix(std::move(st_at_k), new_plan, k_change, N, M);
        }

        if (new_energy < current_energy) {
            current_energy = new_energy;
            current_plan = new_plan;
            if (new_energy < best_energy) {
                best_energy = new_energy;
                best_plan = new_plan;
            }
        } else {
            double delta = new_energy - current_energy;
            if (T > 1e-9 && RGen.a_double(0, 1) < std::exp(-delta / T)) {
                current_energy = new_energy;
                current_plan = new_plan;
            }
        }
        sa_iters++;
    }

    // Output best plan
    SimResult final_res = simulate(init_stacks, best_plan, N, M, true);
    for (auto& op : final_res.ops) {
        std::cout << op.first << " " << op.second << "\n";
    }

    return 0;
}
